import java.io.File;
import java.util.Scanner;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        // Secure file path construction using File.separator to prevent Path Traversal
        String basePath = "C:/temp/";
        String safeFileName = fileName.replaceAll("[^a-zA-Z0-9.-]", ""); // Remove any potentially harmful characters

        File file = new File(basePath + safeFileName);

        // Validate that the resulting file path is within the intended directory
        if (file.getAbsolutePath().startsWith(basePath) && file.exists()) {
            System.out.println("File exists.");
        } else {
            System.out.println("File not found.");
        }
    }
}

